-- Script untuk memasukkan Berita Terbaru berdasarkan postingan Instagram dan Facebook KSPPS MAWAR JATIM

INSERT INTO `news` (`title`, `slug`, `content`, `category`, `thumbnail`, `author_id`, `is_published`, `created_at`, `updated_at`) VALUES
('Kunjungan Silaturahmi dan Rapat Anggota Tahunan KOPMA', 'kunjungan-silaturahmi-dan-rat-kopma', '<p>Alhamdulillah, segenap pengurus KSPPS MAWAR JATIM telah sukses menyelenggarakan Rapat Anggota Tahunan (RAT) serta silaturahmi bersama anggota. Acara ini berlangsung dengan khidmat di lingkungan Pondok Pesantren Matholi''ul Anwar. Dalam kesempatan ini, kami juga menyampaikan berbagai pencapaian positif selama tahun buku terakhir serta berbagai rencana pembiayaan ke depan.</p><p>Bagi anggota yang tidak sempat hadir, dokumentasi lengkap keseruan dan kelancaran acara dapat dilihat secara langsung melalui halaman <strong>Instagram kami @mawarkoperasi</strong>. Jangan lupa untuk <em>follow</em> dan berikan <em>like</em>!</p>', 'kegiatan', 'images.jpg', 1, 1, NOW(), NOW()),

('Penyaluran Program Kesejahteraan dan Baitul Maal', 'penyaluran-kesejahteraan-baitul-maal', '<p>Sebagai wujud dari misi Koperasi Mawar dalam \"Menciptakan kesejahteraan bagi para anggota yang berkesinambungan\", divisi Baitul Maal kembali menyalurkan dana bantuan sosial dan ZIS kepada pihak-pihak yang membutuhkan di sekitar Simo Sungelebak, Karanggeneng, Lamongan.</p><p>Kami mengucapkan terima kasih sebesar-besarnya kepada seluruh anggota yang telah berpartisipasi dan menitipkan kepercayaannya. Informasi detail mengenai program kepedulian ini juga senantiasa kami perbarui melalui <strong>Facebook resmi kami: KSPPS Mawar Jatim</strong>. Mari kita terus tebarkan manfaat untuk sesama.</p>', 'kegiatan', 'images.jpg', 1, 1, NOW(), NOW()),

('Dapatkan Kemudahan Akses Pembiayaan Modal Usaha', 'kemudahan-pembiayaan-modal-usaha-anggota', '<p>Kabar gembira! KSPPS MAWAR JATIM kini mempermudah proses pengajuan produk pembiayaan (seperti Mudharabah dan Musyarakah) bagi anggota yang ingin mengembangkan usahanya atau menambah modal kerja. Dengan sistem syariah yang adil dan bagi hasil yang transparan, koperasi hadir sebagai mitra strategis Anda.</p><p>Konsultasikan kebutuhan usaha Anda kepada tim layanan kami. Dapatkan tips, trik, dan testimoni dari anggota yang telah sukses mengembangkan UMKM-nya di akun <strong>Instagram @mawarkoperasi</strong> dan <strong>Facebook KSPPS Mawar Jatim</strong>.</p>', 'pengumuman', 'images.jpg', 1, 1, NOW(), NOW());
